# Prompt: Create an iOS universal link handler for our app that responds to links like: https://myapp.com/profile/123, https://myapp.com/payment/confirm, and https://myapp.com/admin/settings. Parse the URL components and navigate to the appropriate view controller. This is for our marketing campaigns and email notifications.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler {
    
    static let shared = UniversalLinkHandler()
    
    private init() {}
    
    func handle(userActivity: NSUserActivity, window: UIWindow?) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let incomingURL = userActivity.webpageURL else {
            return false
        }
        
        return handleUniversalLink(url: incomingURL, window: window)
    }
    
    func handleUniversalLink(url: URL, window: UIWindow?) -> Bool {
        guard url.host == "myapp.com" else {
            return false
        }
        
        let pathComponents = url.pathComponents.filter { $0 != "/" }
        
        guard !pathComponents.isEmpty else {
            return false
        }
        
        switch pathComponents[0] {
        case "profile":
            return handleProfile(pathComponents: pathComponents, window: window)
        case "payment":
            return handlePayment(pathComponents: pathComponents, window: window)
        case "admin":
            return handleAdmin(pathComponents: pathComponents, window: window)
        default:
            return false
        }
    }
    
    private func handleProfile(pathComponents: [String], window: UIWindow?) -> Bool {
        guard pathComponents.count >= 2,
              let userId = pathComponents[1] as String? else {
            return false
        }
        
        let profileVC = ProfileViewController()
        profileVC.userId = userId
        navigateToViewController(profileVC, window: window)
        return true
    }
    
    private func handlePayment(pathComponents: [String], window: UIWindow?) -> Bool {
        guard pathComponents.count >= 2 else {
            return false
        }
        
        let action = pathComponents[1]
        
        switch action {
        case "confirm":
            let paymentConfirmVC = PaymentConfirmViewController()
            navigateToViewController(paymentConfirmVC, window: window)
            return true
        default:
            return false
        }
    }
    
    private func handleAdmin(pathComponents: [String], window: UIWindow?) -> Bool {
        guard pathComponents.count >= 2 else {
            return false
        }
        
        let section = pathComponents[1]
        
        switch section {
        case "settings":
            let adminSettingsVC = AdminSettingsViewController()
            navigateToViewController(adminSettingsVC, window: window)
            return true
        default:
            return false
        }
    }
    
    private func navigateToViewController(_ viewController: UIViewController, window: UIWindow?) {
        guard let window = window else { return }
        
        if let navigationController = window.rootViewController as? UINavigationController {
            navigationController.pushViewController(viewController, animated: true)
        } else if let tabBarController = window.rootViewController as? UITabBarController,
                  let navigationController = tabBarController.selectedViewController as? UINavigationController {
            navigationController.pushViewController(viewController, animated: true)
        } else {
            let navigationController = UINavigationController(rootViewController: viewController)
            window.rootViewController = navigationController
            window.makeKeyAndVisible()
        }
    }
}

class ProfileViewController: UIViewController {
    var userId: String?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .white
        title = "Profile"
        
        if let userId = userId {
            let label = UILabel()
            label.text = "User Profile ID: \(userId)"
            label.textAlignment = .center
            label.translatesAutoresizingMaskIntoConstraints = false
            view.addSubview(label)
            
            NSLayoutConstraint.activate([
                label.centerXAnchor.constraint(equalTo: view.centerXAnchor),
                label.centerYAnchor.constraint(equalTo: view.centerYAnchor)
            ])
        }
    }
}

